import{_ as n}from"./plugin-vue_export-helper-DlAUqK2U.js";import{e as a,f as e,o as p}from"./app-BeQLnLll.js";const t={};function i(l,s){return p(),a("div",null,s[0]||(s[0]=[e(`<h1 id="p4-swarm-部署与使用" tabindex="-1"><a class="header-anchor" href="#p4-swarm-部署与使用"><span>P4 Swarm 部署与使用</span></a></h1><p>Swarm 是 Perforce 官方的代码评审 Web 系统,和 Helix Core(P4)集成做 pre-commit / post-commit review。这篇从概念用法讲到部署:在 P4V 里怎么发起和处理 review、Docker 怎么起一个新 Swarm、<code>config.php</code> 怎么配、Nginx 怎么套 HTTPS、一个 Swarm 怎么连多台 P4、怎么触发 Jenkins 构建、API 怎么用、再到接 Claude 做 AI Review,最后是卸载和排错。下文所有内部主机、IP、账号密码都用占位符代替,换成你自己的值即可。</p><h2 id="review-工作流-p4v-端" tabindex="-1"><a class="header-anchor" href="#review-工作流-p4v-端"><span>Review 工作流(P4V 端)</span></a></h2><p>Swarm 网址登录用的账号密码和 P4 一致。P4V 连上启用了 Swarm 集成的 P4 服务后,会在 submitted 和 pending changelist 标签页加上 <strong>Review Id</strong> 和 <strong>Review State</strong> 两列;看不到就在表头右键勾选这两个字段。如果 P4V 里没有 Swarm 连接成功的日志输出,重启 P4V。</p><h3 id="发起-review-requester" tabindex="-1"><a class="header-anchor" href="#发起-review-requester"><span>发起 review(Requester)</span></a></h3><ol><li><strong>右键某个具体的 pending changelist</strong>(不能是 default pending changelist),选 <code>Request New Swarm Review</code>。</li><li>在弹窗里填 reviewer:知道用户名直接输,不知道用 <code>Browse</code> 找。支持多个 reviewer,但至少要有一个是 Required。弹窗还有几个选项: <ul><li><code>Revert checked out files after they are shelved</code>:shelve 后直接取消该 changelist 文件的 checkout。<strong>想在提交 review 后保留本地修改就别勾这个。</strong></li><li><code>Remove files that are opened for add</code>:直接删本地新增的文件。</li><li><code>Don&#39;t shelve unchanged files</code>:不 shelve 未改动的文件。</li></ul></li><li>点 OK。创建成功后自动跳到 Swarm 网站,pending changelist 会带上一个 Swarm 小标签,并自动把待 review 的文件 shelve。Swarm 会自动给 Requester 和 Reviewer 发邮件。</li></ol><p>关于 <code>+l</code>(exclusive lock)状态文件,有个坑要特别注意:</p><ul><li>文件在 P4 上是 <code>+l</code> 状态时,<strong>必须勾选</strong> <code>Revert checked out files after they are shelved</code>,且二进制文件在 Swarm 上不可视。</li><li>如果是 <code>+l</code> 状态却没勾这个选项,那么没人会收到 request 通知,后续即使所有 reviewer 同意也无法在 Swarm 上提交。</li><li>已经对 <code>+l</code> 文件创建了异常的 request,可以先把文件 revert(取消 checkout),再点 <code>Update Swarm Review ...</code> 修复。</li></ul><blockquote><p>如果 request 提交不规范导致 Request 异常,将没人收到邮件,后续会影响提交。</p></blockquote><h3 id="处理-review-reviewer" tabindex="-1"><a class="header-anchor" href="#处理-review-reviewer"><span>处理 review(Reviewer)</span></a></h3><ol><li><p>收到 Requester 邮件,所有待 review 的单子在 Swarm 的 <code>/reviews/</code> 页面能看到。</p></li><li><p><strong>多人投票</strong>:每个 reviewer 在单子页面投票,通过 <code>Vote Up</code>,不通过 <code>Vote Down</code>。只有一个 reviewer 时跳过这步。<strong>只有所有 reviewer 都 Vote Up</strong>,<code>Need Review</code> 下拉框里才会出现 <code>Approve</code>、<code>Approve and Commit</code> 按钮。</p></li><li><p>点开单子,右上角 <code>Need Review</code> 下拉框里选对应回复。各选项含义:</p><table><thead><tr><th>操作</th><th>含义</th></tr></thead><tbody><tr><td>Needs Revision</td><td>要求修改 review 中的文件</td></tr><tr><td>Needs Review</td><td>要求进一步评审</td></tr><tr><td>Approve</td><td>批准(满足投票要求时才可用)</td></tr><tr><td>Commit</td><td>提交(已批准的 pre-commit review 才可用)</td></tr><tr><td>Approve and Commit</td><td>一步批准并提交(未批准但满足投票要求的 pre-commit review)</td></tr><tr><td>Reject</td><td>拒绝,单子移到 closed</td></tr><tr><td>Archive</td><td>归档</td></tr><tr><td>Obliterate Review</td><td>抹除(默认仅 admin/super 用户可用)</td></tr></tbody></table></li></ol><p>点 Approve 单子状态变为已批准并邮件通知双方;点 Approve and Commit 会自动提交该 pending changelist。</p><blockquote><p>reviewer 同意后,<strong>由 reviewer 或 requester 在 Swarm 上点 commit</strong>,Requester 不要在 P4V 上手动提交,否则 Swarm 上没有 review 记录。</p></blockquote><h3 id="更新-review" tabindex="-1"><a class="header-anchor" href="#更新-review"><span>更新 review</span></a></h3><p>高版本 P4V 有 bug,直接右键 <code>update Swarm Review &#39;XXX&#39;</code> 可能用不了。可靠做法:</p><ol><li>新建一个 pending changelist,把改动的文件放进去。</li><li>右键这个新 changelist → <code>update Swarm Review &#39;XXX&#39;</code> → 输入 Review 编号。</li></ol><p>对于 post-commit review、或不是你作者的 review:fetch review 的文件到新 changelist → 改文件 → 在 changelist 描述里加上 <code>#review-12345</code>(和其他文字用空白分隔,或单独一行)→ shelve。</p><h3 id="从-review-取文件" tabindex="-1"><a class="header-anchor" href="#从-review-取文件"><span>从 review 取文件</span></a></h3><p>作为 reviewer 想拿一份本地副本:review id 对应 P4 里一个含这些文件的 pending changelist。在 P4V 用 <code>Go To Spec</code> 对话框输入 review id → P4V 弹出 Pending Changelist 对话框 → 选要 unshelve 的文件 → 右键 Unshelve → 选目标 changelist → Unshelve,文件就拉到本地了。</p><h3 id="评论" tabindex="-1"><a class="header-anchor" href="#评论"><span>评论</span></a></h3><p>支持对文件、对文件中的某一行评论,以及图片评论(把图拖进输入框,单图上限 8MB)、回复评论、给 request/reviewer/评论者发邮件。删错误的 review 也在评论相关菜单里。</p><h2 id="docker-部署" tabindex="-1"><a class="header-anchor" href="#docker-部署"><span>Docker 部署</span></a></h2><p>下面是在一台宿主机上用 Docker 起多个 Swarm 实例的流程。每个实例占一个宿主机端口,记得维护一份端口分配表避免冲突。</p><h3 id="宿主机环境" tabindex="-1"><a class="header-anchor" href="#宿主机环境"><span>宿主机环境</span></a></h3><p>系统用 CentOS。先装 Docker(找 IT 开网络权限),设开机自启:</p><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code><span class="line">systemctl <span class="token builtin class-name">enable</span> docker.service</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>确保 P4 服务器和 Swarm 宿主机能互通。再装 docker-compose,直接下二进制最省事:</p><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code><span class="line"><span class="token comment"># 从 https://github.com/docker/compose/releases/ 下载后</span></span>
<span class="line"><span class="token function">cp</span> docker-compose-linux-x86_64 /usr/local/bin/docker-compose</span>
<span class="line"><span class="token function">chmod</span> +x /usr/local/bin/docker-compose</span>
<span class="line"><span class="token function">ln</span> <span class="token parameter variable">-s</span> /usr/local/bin/docker-compose /usr/bin/docker-compose</span>
<span class="line"><span class="token function">docker-compose</span> <span class="token parameter variable">-v</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="起一个新-swarm" tabindex="-1"><a class="header-anchor" href="#起一个新-swarm"><span>起一个新 Swarm</span></a></h3><p>建项目目录(同宿主机多 Swarm,命名保持统一):</p><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code><span class="line"><span class="token builtin class-name">cd</span> ~</span>
<span class="line"><span class="token function">mkdir</span> projectName-swarm</span>
<span class="line"><span class="token builtin class-name">cd</span> projectName-swarm</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong><code>.env</code> 文件</strong>(只改下面这些。<code>/opt/perforce/swarm/data/</code> 下没有 <code>config.php</code> 时才用 <code>.env</code>):</p><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code><span class="line"><span class="token assign-left variable">project</span><span class="token operator">=</span><span class="token operator">&lt;</span>project-name<span class="token operator">&gt;</span>              <span class="token comment"># 项目名</span></span>
<span class="line"><span class="token assign-left variable">port</span><span class="token operator">=</span><span class="token operator">&lt;</span>swarm-port<span class="token operator">&gt;</span>                   <span class="token comment"># Swarm 端口</span></span>
<span class="line"><span class="token assign-left variable">image</span><span class="token operator">=</span>perforce/helix-swarm:2023     <span class="token comment"># Swarm 镜像版本</span></span>
<span class="line"><span class="token assign-left variable">hostip</span><span class="token operator">=</span><span class="token operator">&lt;</span>swarm-host<span class="token operator">&gt;</span>                 <span class="token comment"># Swarm 宿主机 IP</span></span>
<span class="line"></span>
<span class="line"><span class="token assign-left variable">P4D_PORT</span><span class="token operator">=</span><span class="token operator">&lt;</span>P4SERVER<span class="token operator">&gt;</span>:1666            <span class="token comment"># P4 server 端口</span></span>
<span class="line"><span class="token assign-left variable">P4D_SUPER</span><span class="token operator">=</span><span class="token operator">&lt;</span>p4-super-user<span class="token operator">&gt;</span>           <span class="token comment"># P4 超级用户,登录设为永不过期!!!</span></span>
<span class="line"><span class="token assign-left variable">P4D_SUPER_PASSWD</span><span class="token operator">=</span><span class="token operator">&lt;</span>P4-PASSWORD<span class="token operator">&gt;</span>      <span class="token comment"># P4 超级用户密码</span></span>
<span class="line"><span class="token assign-left variable">SWARM_USER</span><span class="token operator">=</span><span class="token operator">&lt;</span>p4-super-user<span class="token operator">&gt;</span>          <span class="token comment"># P4 超级用户,登录设为永不过期!!!</span></span>
<span class="line"><span class="token assign-left variable">SWARM_PASSWD</span><span class="token operator">=</span><span class="token operator">&lt;</span>P4-PASSWORD<span class="token operator">&gt;</span>          <span class="token comment"># P4 超级用户密码</span></span>
<span class="line"></span>
<span class="line"><span class="token assign-left variable">SWARM_HOST</span><span class="token operator">=</span><span class="token variable">$hostip</span><span class="token builtin class-name">:</span><span class="token variable">$port</span></span>
<span class="line"><span class="token assign-left variable">SWARM_MAILHOST</span><span class="token operator">=</span>smtp.office365.com</span>
<span class="line"></span>
<span class="line"><span class="token assign-left variable">SWARM_REDIS</span><span class="token operator">=</span>helix-redis-<span class="token variable">$project</span></span>
<span class="line"><span class="token assign-left variable">SWARM_REDIS_PORT</span><span class="token operator">=</span><span class="token number">7379</span></span>
<span class="line"></span>
<span class="line"><span class="token comment"># 设为 &#39;y&#39; 则即使扩展已存在也会重装并覆盖现有配置</span></span>
<span class="line"><span class="token assign-left variable">SWARM_FORCE_EXT</span><span class="token operator">=</span>y</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong><code>docker-compose.yml</code></strong>(无需改动):</p><div class="language-yaml line-numbers-mode" data-highlighter="prismjs" data-ext="yml"><pre><code><span class="line"><span class="token key atrule">version</span><span class="token punctuation">:</span> <span class="token string">&#39;2.11&#39;</span></span>
<span class="line"><span class="token key atrule">networks</span><span class="token punctuation">:</span></span>
<span class="line">  <span class="token key atrule">default</span><span class="token punctuation">:</span></span>
<span class="line">    <span class="token key atrule">driver</span><span class="token punctuation">:</span> bridge</span>
<span class="line">    <span class="token key atrule">name</span><span class="token punctuation">:</span> swarm<span class="token punctuation">-</span>$<span class="token punctuation">{</span>project<span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"><span class="token key atrule">services</span><span class="token punctuation">:</span></span>
<span class="line">  <span class="token key atrule">swarm</span><span class="token punctuation">:</span></span>
<span class="line">    <span class="token key atrule">image</span><span class="token punctuation">:</span> $<span class="token punctuation">{</span>image<span class="token punctuation">}</span></span>
<span class="line">    <span class="token key atrule">container_name</span><span class="token punctuation">:</span> helix<span class="token punctuation">-</span>swarm<span class="token punctuation">-</span>$<span class="token punctuation">{</span>project<span class="token punctuation">}</span></span>
<span class="line">    <span class="token key atrule">domainname</span><span class="token punctuation">:</span> helix</span>
<span class="line">    <span class="token key atrule">volumes</span><span class="token punctuation">:</span></span>
<span class="line">      <span class="token punctuation">-</span> $PWD/swarm<span class="token punctuation">-</span>data<span class="token punctuation">:</span>/opt/perforce/swarm/data</span>
<span class="line">    <span class="token key atrule">ports</span><span class="token punctuation">:</span></span>
<span class="line">      <span class="token punctuation">-</span> 0.0.0.0<span class="token punctuation">:</span>$<span class="token punctuation">{</span>port<span class="token punctuation">}</span><span class="token punctuation">:</span>$<span class="token punctuation">{</span>port<span class="token punctuation">}</span></span>
<span class="line">    <span class="token key atrule">working_dir</span><span class="token punctuation">:</span> /opt/perforce/swarm</span>
<span class="line">    <span class="token key atrule">depends_on</span><span class="token punctuation">:</span></span>
<span class="line">      <span class="token punctuation">-</span> redis</span>
<span class="line">    <span class="token key atrule">tty</span><span class="token punctuation">:</span> <span class="token boolean important">false</span></span>
<span class="line">    <span class="token key atrule">env_file</span><span class="token punctuation">:</span> $PWD/.env</span>
<span class="line">    <span class="token key atrule">restart</span><span class="token punctuation">:</span> always</span>
<span class="line"></span>
<span class="line">  <span class="token key atrule">redis</span><span class="token punctuation">:</span></span>
<span class="line">    <span class="token key atrule">image</span><span class="token punctuation">:</span> <span class="token string">&quot;redis&quot;</span></span>
<span class="line">    <span class="token key atrule">container_name</span><span class="token punctuation">:</span> helix<span class="token punctuation">-</span>redis<span class="token punctuation">-</span>$<span class="token punctuation">{</span>project<span class="token punctuation">}</span></span>
<span class="line">    <span class="token key atrule">domainname</span><span class="token punctuation">:</span> helix</span>
<span class="line">    <span class="token key atrule">command</span><span class="token punctuation">:</span> redis<span class="token punctuation">-</span>server <span class="token punctuation">-</span><span class="token punctuation">-</span>protected<span class="token punctuation">-</span>mode no <span class="token punctuation">-</span><span class="token punctuation">-</span>port 7379 <span class="token punctuation">-</span><span class="token punctuation">-</span>appendonly yes</span>
<span class="line">    <span class="token key atrule">volumes</span><span class="token punctuation">:</span></span>
<span class="line">      <span class="token punctuation">-</span> $PWD/redis<span class="token punctuation">-</span>data<span class="token punctuation">:</span>/data</span>
<span class="line">    <span class="token key atrule">restart</span><span class="token punctuation">:</span> always</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong><code>crontab</code> 文件</strong>:改了 Swarm 端口后 worker cron 会失效,所以单独建一个 cron job。从 <code>/etc/crontab</code> 拷个模板,末尾加上这一行:</p><div class="language-text line-numbers-mode" data-highlighter="prismjs" data-ext="text"><pre><code><span class="line">* * * * * root [ -x /opt/perforce/swarm/p4-bin/scripts/swarm-cron.sh ] &amp;&amp; /opt/perforce/swarm/p4-bin/scripts/swarm-cron.sh</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p><strong><code>start-new-swarm.sh</code></strong>(无需改动):起容器、等 5 分钟初始化、改 Apache 站点和 cron 配置里的端口、重启、再把 crontab 拷进容器:</p><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code><span class="line"><span class="token builtin class-name">set</span> <span class="token parameter variable">-a</span></span>
<span class="line"><span class="token builtin class-name">source</span> <span class="token environment constant">$PWD</span>/.env</span>
<span class="line"><span class="token builtin class-name">set</span> +a</span>
<span class="line"></span>
<span class="line"><span class="token function">mkdir</span> <span class="token parameter variable">-p</span> redis-data</span>
<span class="line"><span class="token function">mkdir</span> <span class="token parameter variable">-p</span> swarm-data</span>
<span class="line"><span class="token function">docker-compose</span> up <span class="token parameter variable">-d</span></span>
<span class="line"><span class="token function">sleep</span> 5m</span>
<span class="line"></span>
<span class="line"><span class="token function">sed</span> <span class="token parameter variable">-i</span> <span class="token string">&quot;1i\\Listen <span class="token variable">$port</span>&quot;</span> swarm-data/docker/sites-available/perforce-swarm-site.conf</span>
<span class="line"><span class="token function">sed</span> <span class="token parameter variable">-i</span> <span class="token string">&quot;s/80/<span class="token variable">$port</span>/g&quot;</span> swarm-data/docker/sites-available/perforce-swarm-site.conf</span>
<span class="line"><span class="token function">sed</span> <span class="token parameter variable">-i</span> <span class="token string">&quot;s/80/<span class="token variable">$port</span>/g&quot;</span> swarm-data/docker/swarm-cron-hosts.conf</span>
<span class="line"></span>
<span class="line"><span class="token function">docker-compose</span> down</span>
<span class="line"><span class="token function">docker-compose</span> up <span class="token parameter variable">-d</span></span>
<span class="line"><span class="token function">docker</span> <span class="token function">cp</span> <span class="token function">crontab</span> <span class="token variable"><span class="token variable">$(</span><span class="token function">docker</span> <span class="token function">ps</span> <span class="token parameter variable">-aqf</span> <span class="token string">&quot;name=helix-swarm-<span class="token variable">$project</span>&quot;</span><span class="token variable">)</span></span>:/etc/crontab</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>启动并等约 5 分钟:</p><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code><span class="line"><span class="token function">chmod</span> +x ./start-new-swarm.sh</span>
<span class="line">./start-new-swarm.sh</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><p>P4 用 SSL 时,进容器建立信任:</p><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code><span class="line"><span class="token function">docker</span> <span class="token function">ps</span> <span class="token parameter variable">-a</span></span>
<span class="line"><span class="token function">docker</span> <span class="token builtin class-name">exec</span> <span class="token parameter variable">-it</span> <span class="token operator">&lt;</span>container-id<span class="token operator">&gt;</span> /bin/bash</span>
<span class="line">p4 <span class="token parameter variable">-p</span> ssl:<span class="token operator">&lt;</span>P4SERVER<span class="token operator">&gt;</span>:1666 trust</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>重启 Swarm:</p><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code><span class="line"><span class="token function">docker-compose</span> stop</span>
<span class="line"><span class="token function">docker-compose</span> start</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><blockquote><p>不要删容器。如果删了容器再重启,需要重新拷一次 crontab,否则网页会显示没有 worker、导致 Swarm 不可用:</p><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code><span class="line"><span class="token function">docker</span> <span class="token function">cp</span> <span class="token function">crontab</span> <span class="token variable"><span class="token variable">$(</span><span class="token function">docker</span> <span class="token function">ps</span> <span class="token parameter variable">-aqf</span> <span class="token string">&quot;name=helix-swarm-<span class="token variable">$project</span>&quot;</span><span class="token variable">)</span></span>:/etc/crontab</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div></blockquote><p>最后建一个名为 <code>.swarm</code> 的 P4 depot,用于图片评论附件存储。如果 P4V 连不上 Swarm,检查并设置 Swarm URL:</p><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code><span class="line">p4 property <span class="token parameter variable">-l</span> <span class="token parameter variable">-A</span></span>
<span class="line">p4 <span class="token parameter variable">-p</span> <span class="token string">&quot;&lt;P4SERVER&gt;:1666&quot;</span> property <span class="token parameter variable">-a</span> <span class="token parameter variable">-n</span> P4.Swarm.URL <span class="token parameter variable">-v</span> <span class="token string">&quot;http://&lt;swarm-host&gt;:&lt;port&gt;&quot;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="升级-swarm-版本" tabindex="-1"><a class="header-anchor" href="#升级-swarm-版本"><span>升级 Swarm 版本</span></a></h3><p>切到 <code>projectName-swarm</code> 目录:</p><ol><li><code>docker-compose down</code> 删当前容器。</li><li><code>docker pull perforce/helix-swarm:&lt;新版本&gt;</code> 下镜像(机器上没有时)。</li><li>备份当前 <code>projectName-swarm</code> 目录,准备新起一个。</li><li>更新 <code>.env</code> 里的 <code>image</code> 版本。</li><li><code>./start-new-swarm.sh</code> 起新 Swarm。</li><li>重新改 <code>config.php</code>,在网页 reload 配置。</li></ol><h2 id="配置文件-config-php" tabindex="-1"><a class="header-anchor" href="#配置文件-config-php"><span>配置文件 config.php</span></a></h2><p><code>config.php</code> 是 Swarm 的配置文件,位于 <code>/opt/perforce/swarm/data/config.php</code>。Docker 部署时改 <code>swarm-data/config.php</code>。改完后在网页 <code>System Information → Cache Info → Reload Configuration</code> 使配置生效(Swarm 会缓存这个文件,不 reload 不会被读取)。</p><p>基本结构如下,把所有密钥/主机替换成你自己的值:</p><div class="language-php line-numbers-mode" data-highlighter="prismjs" data-ext="php"><pre><code><span class="line"><span class="token php language-php"><span class="token delimiter important">&lt;?php</span></span>
<span class="line"><span class="token comment">/* WARNING: The contents of this file is cached by Swarm. Changes to</span>
<span class="line"> * it will not be picked up until the cached versions are removed.</span>
<span class="line"> */</span></span>
<span class="line"><span class="token keyword">return</span> <span class="token keyword">array</span><span class="token punctuation">(</span></span>
<span class="line">    <span class="token string single-quoted-string">&#39;environment&#39;</span> <span class="token operator">=&gt;</span> <span class="token keyword">array</span><span class="token punctuation">(</span></span>
<span class="line">        <span class="token string single-quoted-string">&#39;hostname&#39;</span> <span class="token operator">=&gt;</span> <span class="token string single-quoted-string">&#39;&lt;swarm-host&gt;:&lt;port&gt;&#39;</span><span class="token punctuation">,</span></span>
<span class="line">    <span class="token punctuation">)</span><span class="token punctuation">,</span></span>
<span class="line">    <span class="token string single-quoted-string">&#39;p4&#39;</span> <span class="token operator">=&gt;</span> <span class="token keyword">array</span><span class="token punctuation">(</span></span>
<span class="line">        <span class="token string single-quoted-string">&#39;port&#39;</span>     <span class="token operator">=&gt;</span> <span class="token string single-quoted-string">&#39;&lt;P4SERVER&gt;:1666&#39;</span><span class="token punctuation">,</span></span>
<span class="line">        <span class="token string single-quoted-string">&#39;user&#39;</span>     <span class="token operator">=&gt;</span> <span class="token string single-quoted-string">&#39;&lt;p4-super-user&gt;&#39;</span><span class="token punctuation">,</span></span>
<span class="line">        <span class="token string single-quoted-string">&#39;password&#39;</span> <span class="token operator">=&gt;</span> <span class="token string single-quoted-string">&#39;&lt;P4-PASSWORD&gt;&#39;</span><span class="token punctuation">,</span>          <span class="token comment">// P4 ticket 或密码</span></span>
<span class="line">    <span class="token punctuation">)</span><span class="token punctuation">,</span></span>
<span class="line">    <span class="token string single-quoted-string">&#39;mail&#39;</span> <span class="token operator">=&gt;</span> <span class="token keyword">array</span><span class="token punctuation">(</span></span>
<span class="line">        <span class="token string single-quoted-string">&#39;sender&#39;</span> <span class="token operator">=&gt;</span> <span class="token string single-quoted-string">&#39;&lt;sender@example.com&gt;&#39;</span><span class="token punctuation">,</span></span>
<span class="line">        <span class="token string single-quoted-string">&#39;transport&#39;</span> <span class="token operator">=&gt;</span> <span class="token keyword">array</span><span class="token punctuation">(</span></span>
<span class="line">            <span class="token string single-quoted-string">&#39;host&#39;</span> <span class="token operator">=&gt;</span> <span class="token string single-quoted-string">&#39;smtp.office365.com&#39;</span><span class="token punctuation">,</span></span>
<span class="line">            <span class="token string single-quoted-string">&#39;port&#39;</span> <span class="token operator">=&gt;</span> <span class="token number">587</span><span class="token punctuation">,</span></span>
<span class="line">            <span class="token string single-quoted-string">&#39;connection_class&#39;</span>  <span class="token operator">=&gt;</span> <span class="token string single-quoted-string">&#39;login&#39;</span><span class="token punctuation">,</span></span>
<span class="line">            <span class="token string single-quoted-string">&#39;connection_config&#39;</span> <span class="token operator">=&gt;</span> <span class="token keyword">array</span><span class="token punctuation">(</span></span>
<span class="line">                <span class="token string single-quoted-string">&#39;username&#39;</span> <span class="token operator">=&gt;</span> <span class="token string single-quoted-string">&#39;&lt;mail-user&gt;&#39;</span><span class="token punctuation">,</span></span>
<span class="line">                <span class="token string single-quoted-string">&#39;password&#39;</span> <span class="token operator">=&gt;</span> <span class="token string single-quoted-string">&#39;&lt;SMTP-PASSWORD&gt;&#39;</span><span class="token punctuation">,</span></span>
<span class="line">                <span class="token string single-quoted-string">&#39;ssl&#39;</span> <span class="token operator">=&gt;</span> <span class="token string single-quoted-string">&#39;tls&#39;</span><span class="token punctuation">,</span></span>
<span class="line">            <span class="token punctuation">)</span><span class="token punctuation">,</span></span>
<span class="line">        <span class="token punctuation">)</span><span class="token punctuation">,</span></span>
<span class="line">    <span class="token punctuation">)</span><span class="token punctuation">,</span></span>
<span class="line">    <span class="token string single-quoted-string">&#39;queue&#39;</span> <span class="token operator">=&gt;</span> <span class="token keyword">array</span><span class="token punctuation">(</span></span>
<span class="line">        <span class="token string single-quoted-string">&#39;workers&#39;</span>             <span class="token operator">=&gt;</span> <span class="token number">8</span><span class="token punctuation">,</span>    <span class="token comment">// 默认 3</span></span>
<span class="line">        <span class="token string single-quoted-string">&#39;worker_lifetime&#39;</span>     <span class="token operator">=&gt;</span> <span class="token number">595</span><span class="token punctuation">,</span>  <span class="token comment">// 默认 10 分钟少 5 秒</span></span>
<span class="line">        <span class="token string single-quoted-string">&#39;worker_task_timeout&#39;</span> <span class="token operator">=&gt;</span> <span class="token number">1800</span><span class="token punctuation">,</span> <span class="token comment">// 默认 30 分钟</span></span>
<span class="line">        <span class="token string single-quoted-string">&#39;worker_memory_limit&#39;</span> <span class="token operator">=&gt;</span> <span class="token string single-quoted-string">&#39;1G&#39;</span><span class="token punctuation">,</span> <span class="token comment">// 默认 1G</span></span>
<span class="line">    <span class="token punctuation">)</span><span class="token punctuation">,</span></span>
<span class="line">    <span class="token string single-quoted-string">&#39;reviews&#39;</span> <span class="token operator">=&gt;</span> <span class="token keyword">array</span><span class="token punctuation">(</span></span>
<span class="line">        <span class="token string single-quoted-string">&#39;cleanup&#39;</span> <span class="token operator">=&gt;</span> <span class="token keyword">array</span><span class="token punctuation">(</span></span>
<span class="line">            <span class="token string single-quoted-string">&#39;mode&#39;</span>        <span class="token operator">=&gt;</span> <span class="token string single-quoted-string">&#39;auto&#39;</span><span class="token punctuation">,</span>  <span class="token comment">// auto 跟随默认 / user 展示勾选框</span></span>
<span class="line">            <span class="token string single-quoted-string">&#39;default&#39;</span>     <span class="token operator">=&gt;</span> <span class="token constant boolean">true</span><span class="token punctuation">,</span>    <span class="token comment">// commit 时清理 pending changelist</span></span>
<span class="line">            <span class="token string single-quoted-string">&#39;reopenFiles&#39;</span> <span class="token operator">=&gt;</span> <span class="token constant boolean">false</span><span class="token punctuation">,</span>   <span class="token comment">// 把打开的文件重开到 default changelist</span></span>
<span class="line">        <span class="token punctuation">)</span><span class="token punctuation">,</span></span>
<span class="line">    <span class="token punctuation">)</span><span class="token punctuation">,</span></span>
<span class="line">    <span class="token string single-quoted-string">&#39;log&#39;</span> <span class="token operator">=&gt;</span> <span class="token keyword">array</span><span class="token punctuation">(</span></span>
<span class="line">        <span class="token string single-quoted-string">&#39;priority&#39;</span>     <span class="token operator">=&gt;</span> <span class="token number">3</span><span class="token punctuation">,</span></span>
<span class="line">        <span class="token string single-quoted-string">&#39;reference_id&#39;</span> <span class="token operator">=&gt;</span> <span class="token constant boolean">true</span><span class="token punctuation">,</span></span>
<span class="line">    <span class="token punctuation">)</span><span class="token punctuation">,</span></span>
<span class="line">    <span class="token string single-quoted-string">&#39;redis&#39;</span> <span class="token operator">=&gt;</span> <span class="token keyword">array</span><span class="token punctuation">(</span></span>
<span class="line">        <span class="token string single-quoted-string">&#39;options&#39;</span> <span class="token operator">=&gt;</span> <span class="token keyword">array</span><span class="token punctuation">(</span></span>
<span class="line">            <span class="token string single-quoted-string">&#39;server&#39;</span> <span class="token operator">=&gt;</span> <span class="token keyword">array</span><span class="token punctuation">(</span></span>
<span class="line">                <span class="token string single-quoted-string">&#39;host&#39;</span> <span class="token operator">=&gt;</span> <span class="token string single-quoted-string">&#39;helix-redis-&lt;project&gt;&#39;</span><span class="token punctuation">,</span></span>
<span class="line">                <span class="token string single-quoted-string">&#39;port&#39;</span> <span class="token operator">=&gt;</span> <span class="token number">7379</span><span class="token punctuation">,</span></span>
<span class="line">            <span class="token punctuation">)</span><span class="token punctuation">,</span></span>
<span class="line">        <span class="token punctuation">)</span><span class="token punctuation">,</span></span>
<span class="line">    <span class="token punctuation">)</span><span class="token punctuation">,</span></span>
<span class="line">    <span class="token comment">// notifications 各事件的 is_self/is_author/is_reviewer/is_moderator 开关按需配置</span></span>
<span class="line"><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"></span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>几点说明:</p><ul><li><p><code>queue</code> 块控制 worker。<code>workers</code> 是 worker 进程数(默认 3),cron job 会按需拉起新 worker,达到上限就不再起;<code>worker_lifetime</code> 是单个 worker 运行时长上限(默认 595 秒),超时会做完当前任务再退出,不会中途打断任务;<code>worker_task_timeout</code> 是单任务处理上限(默认 1800 秒),用来终结卡死的 worker;<code>worker_memory_limit</code> 是单 worker 内存上限(默认 1G)。</p></li><li><p>改 P4 server IP 后,清缓存重新配置:</p><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code><span class="line"><span class="token function">rm</span> <span class="token parameter variable">-r</span> /opt/perforce/swarm/data/cache</span>
<span class="line"><span class="token function">rm</span> /opt/perforce/swarm/data/config.php.*</span>
<span class="line"><span class="token function">sudo</span> /opt/perforce/swarm/sbin/configure-swarm.sh</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div></li><li><p>邮件用 Office365 时,要联系 IT 把 Swarm 机器 IP 加进新邮件服务器白名单;并确保配置的邮箱账号能正常发邮件。</p></li></ul><h3 id="从包安装-非-docker" tabindex="-1"><a class="header-anchor" href="#从包安装-非-docker"><span>从包安装(非 Docker)</span></a></h3><p>如果不用 Docker,Swarm 也有 Debian(<code>.deb</code>,Ubuntu)和 RPM(<code>.rpm</code>,CentOS/RHEL)包。P4 服务器和 Swarm 服务器分开,Swarm 建议装在 Ubuntu 上,且 P4 服务器要先装好。装前先 <code>telnet &lt;P4SERVER&gt; 1666</code> 确认能连到 P4。</p><p>大致步骤:配 Perforce 包仓库 → 导入签名 key → <code>apt-get install helix-swarm</code>(主包)、<code>helix-swarm-triggers</code>(在 P4 服务器上装)、<code>helix-swarm-optional</code>(可选包)。装完跑交互式配置:</p><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code><span class="line"><span class="token function">sudo</span> /opt/perforce/swarm/sbin/configure-swarm.sh</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>配置脚本会依次问:<code>P4PORT</code>(形如 <code>my-helix-core-server:1666</code>)、一个有 admin 权限的普通 P4 用户的 userid 和登录 ticket/密码(默认 userid 是 <code>swarm</code>)、Swarm UI 的 hostname(域名,找 IT 要)、邮件 relay 主机。</p><p>如果 P4 服务器不能用包(比如跑 Windows),要把 trigger 脚本 <code>/opt/perforce/swarm/p4-bin/scripts/swarm-trigger.pl</code> 拷到 P4 服务器,提交到 <code>//.swarm/triggers/swarm-trigger.pl</code>,并把 <code>/opt/perforce/etc/swarm-trigger.conf</code> 提交到 <code>//.swarm/triggers/swarm-trigger.conf</code>,从 Swarm 取 <code>SWARM_TOKEN</code> 填进去。trigger 依赖 perl 5.08+,Windows 上 JSON 模块随 Strawberry Perl 自带。还要让 P4 把所有 shelved change 都 promote(pre-commit review 的前提):</p><div class="language-bat line-numbers-mode" data-highlighter="prismjs" data-ext="bat"><pre><code><span class="line">p4 configure set dm.shelve.promote=1</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h2 id="https-nginx-反向代理" tabindex="-1"><a class="header-anchor" href="#https-nginx-反向代理"><span>HTTPS:Nginx 反向代理</span></a></h2><p>让 Swarm 走 HTTPS 的思路是用 Nginx 做反向代理:浏览器访问 <code>https://&lt;swarm-url&gt;:8443</code>,Nginx 用 SSL 证书加密通信,再把请求代理到本地 Swarm 服务 <code>http://localhost:&lt;swarm-port&gt;</code>,响应原路加密返回。</p><p>装 Nginx(CentOS,配官方仓库):</p><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code><span class="line"><span class="token function">sudo</span> <span class="token function">vi</span> /etc/yum.repos.d/nginx.repo</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><div class="language-ini line-numbers-mode" data-highlighter="prismjs" data-ext="ini"><pre><code><span class="line"><span class="token section"><span class="token punctuation">[</span><span class="token section-name selector">nginx-stable</span><span class="token punctuation">]</span></span></span>
<span class="line"><span class="token key attr-name">name</span><span class="token punctuation">=</span><span class="token value attr-value">nginx stable repo</span></span>
<span class="line"><span class="token key attr-name">baseurl</span><span class="token punctuation">=</span><span class="token value attr-value">http://nginx.org/packages/centos/$releasever/$basearch/</span></span>
<span class="line"><span class="token key attr-name">gpgcheck</span><span class="token punctuation">=</span><span class="token value attr-value">1</span></span>
<span class="line"><span class="token key attr-name">enabled</span><span class="token punctuation">=</span><span class="token value attr-value">1</span></span>
<span class="line"><span class="token key attr-name">gpgkey</span><span class="token punctuation">=</span><span class="token value attr-value">https://nginx.org/keys/nginx_signing.key</span></span>
<span class="line"><span class="token key attr-name">module_hotfixes</span><span class="token punctuation">=</span><span class="token value attr-value">true</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code><span class="line"><span class="token function">sudo</span> yum clean all <span class="token operator">&amp;&amp;</span> <span class="token function">sudo</span> yum makecache</span>
<span class="line"><span class="token function">sudo</span> yum <span class="token function">install</span> nginx <span class="token parameter variable">-y</span></span>
<span class="line"><span class="token function">sudo</span> systemctl start nginx <span class="token operator">&amp;&amp;</span> <span class="token function">sudo</span> systemctl <span class="token builtin class-name">enable</span> nginx</span>
<span class="line"><span class="token function">sudo</span> systemctl status nginx</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>上传证书和私钥到安全目录并设权限(只 root 可读私钥):</p><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code><span class="line"><span class="token function">sudo</span> <span class="token function">mkdir</span> <span class="token parameter variable">-p</span> /etc/ssl/private</span>
<span class="line"><span class="token function">sudo</span> <span class="token function">cp</span> wildcard.pem /etc/ssl/private/</span>
<span class="line"><span class="token function">sudo</span> <span class="token function">cp</span> wildcard.key /etc/ssl/private/</span>
<span class="line"><span class="token function">sudo</span> <span class="token function">chmod</span> <span class="token number">600</span> /etc/ssl/private/wildcard.key</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>配置反向代理(<code>/etc/nginx/conf.d/swarm.conf</code>):</p><div class="language-nginx line-numbers-mode" data-highlighter="prismjs" data-ext="nginx"><pre><code><span class="line"><span class="token directive"><span class="token keyword">server</span></span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token directive"><span class="token keyword">listen</span> <span class="token number">8443</span> ssl</span><span class="token punctuation">;</span></span>
<span class="line">    <span class="token directive"><span class="token keyword">server_name</span> &lt;swarm-url&gt;</span><span class="token punctuation">;</span>          <span class="token comment"># 替换为你的域名</span></span>
<span class="line"></span>
<span class="line">    <span class="token directive"><span class="token keyword">ssl_certificate</span>     /etc/ssl/private/wildcard.pem</span><span class="token punctuation">;</span></span>
<span class="line">    <span class="token directive"><span class="token keyword">ssl_certificate_key</span> /etc/ssl/private/wildcard.key</span><span class="token punctuation">;</span></span>
<span class="line">    <span class="token directive"><span class="token keyword">ssl_protocols</span>       TLSv1.2 TLSv1.3</span><span class="token punctuation">;</span></span>
<span class="line">    <span class="token directive"><span class="token keyword">ssl_ciphers</span>         <span class="token string">&#39;ECDHE-RSA-AES256-GCM-SHA384:ECDHE-RSA-AES128-GCM-SHA256&#39;</span></span><span class="token punctuation">;</span></span>
<span class="line">    <span class="token directive"><span class="token keyword">ssl_prefer_server_ciphers</span> <span class="token boolean">on</span></span><span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line">    <span class="token directive"><span class="token keyword">location</span> /</span> <span class="token punctuation">{</span></span>
<span class="line">        <span class="token directive"><span class="token keyword">proxy_pass</span> http://localhost:&lt;swarm-port&gt;</span><span class="token punctuation">;</span>   <span class="token comment"># Swarm 容器内部地址端口</span></span>
<span class="line">        <span class="token directive"><span class="token keyword">proxy_set_header</span> Host <span class="token variable">$host</span></span><span class="token punctuation">;</span></span>
<span class="line">        <span class="token directive"><span class="token keyword">proxy_set_header</span> X-Real-IP <span class="token variable">$remote_addr</span></span><span class="token punctuation">;</span></span>
<span class="line">        <span class="token directive"><span class="token keyword">proxy_set_header</span> X-Forwarded-For <span class="token variable">$proxy_add_x_forwarded_for</span></span><span class="token punctuation">;</span></span>
<span class="line">        <span class="token directive"><span class="token keyword">proxy_set_header</span> X-Forwarded-Proto <span class="token variable">$scheme</span></span><span class="token punctuation">;</span></span>
<span class="line">    <span class="token punctuation">}</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>验证并 reload:</p><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code><span class="line"><span class="token function">sudo</span> nginx <span class="token parameter variable">-t</span></span>
<span class="line"><span class="token function">sudo</span> systemctl reload nginx</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><p>一个 IP 上多实例就配多个 <code>server</code> 块,用不同的 listen 端口(如 8443→8130、9443→8132)各自 <code>proxy_pass</code> 到对应 Swarm 端口即可。</p><h2 id="一个-swarm-连多台-p4" tabindex="-1"><a class="header-anchor" href="#一个-swarm-连多台-p4"><span>一个 Swarm 连多台 P4</span></a></h2><p>官方文档:<a href="https://www.perforce.com/manuals/swarm-admin/Content/Swarm/admin_multiple_p4d_config.html" target="_blank" rel="noopener noreferrer">多 Helix Core 实例配置</a>。</p><p>在<strong>全局</strong> <code>config.php</code> 里给每台 P4 加一个 label,填各自连接信息:</p><div class="language-php line-numbers-mode" data-highlighter="prismjs" data-ext="php"><pre><code><span class="line"><span class="token php language-php"><span class="token delimiter important">&lt;?php</span></span>
<span class="line"><span class="token keyword">return</span> <span class="token keyword">array</span><span class="token punctuation">(</span></span>
<span class="line">    <span class="token string single-quoted-string">&#39;p4&#39;</span> <span class="token operator">=&gt;</span> <span class="token keyword">array</span><span class="token punctuation">(</span></span>
<span class="line">        <span class="token string single-quoted-string">&#39;serverA&#39;</span> <span class="token operator">=&gt;</span> <span class="token keyword">array</span><span class="token punctuation">(</span></span>
<span class="line">            <span class="token string single-quoted-string">&#39;port&#39;</span>     <span class="token operator">=&gt;</span> <span class="token string single-quoted-string">&#39;&lt;p4d-A&gt;:1666&#39;</span><span class="token punctuation">,</span></span>
<span class="line">            <span class="token string single-quoted-string">&#39;user&#39;</span>     <span class="token operator">=&gt;</span> <span class="token string single-quoted-string">&#39;&lt;admin-user-A&gt;&#39;</span><span class="token punctuation">,</span></span>
<span class="line">            <span class="token string single-quoted-string">&#39;password&#39;</span> <span class="token operator">=&gt;</span> <span class="token string single-quoted-string">&#39;&lt;P4-PASSWORD&gt;&#39;</span><span class="token punctuation">,</span></span>
<span class="line">            <span class="token string single-quoted-string">&#39;sso&#39;</span>      <span class="token operator">=&gt;</span> <span class="token string single-quoted-string">&#39;disabled&#39;</span><span class="token punctuation">,</span> <span class="token comment">// disabled|optional|enabled</span></span>
<span class="line">        <span class="token punctuation">)</span><span class="token punctuation">,</span></span>
<span class="line">        <span class="token string single-quoted-string">&#39;serverB&#39;</span> <span class="token operator">=&gt;</span> <span class="token keyword">array</span><span class="token punctuation">(</span></span>
<span class="line">            <span class="token string single-quoted-string">&#39;port&#39;</span>     <span class="token operator">=&gt;</span> <span class="token string single-quoted-string">&#39;&lt;p4d-B&gt;:1666&#39;</span><span class="token punctuation">,</span></span>
<span class="line">            <span class="token string single-quoted-string">&#39;user&#39;</span>     <span class="token operator">=&gt;</span> <span class="token string single-quoted-string">&#39;&lt;admin-user-B&gt;&#39;</span><span class="token punctuation">,</span></span>
<span class="line">            <span class="token string single-quoted-string">&#39;password&#39;</span> <span class="token operator">=&gt;</span> <span class="token string single-quoted-string">&#39;&lt;P4-PASSWORD&gt;&#39;</span><span class="token punctuation">,</span></span>
<span class="line">            <span class="token string single-quoted-string">&#39;sso&#39;</span>      <span class="token operator">=&gt;</span> <span class="token string single-quoted-string">&#39;disabled&#39;</span><span class="token punctuation">,</span></span>
<span class="line">        <span class="token punctuation">)</span><span class="token punctuation">,</span></span>
<span class="line">    <span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"></span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>要单独配某台 P4,在 <code>&lt;swarm_root&gt;/data/servers/&lt;serverid&gt;</code> 目录加一个 <code>config.php</code>。注意:</p><ul><li>必须有全局 <code>config.php</code> 来声明这些 P4 实例。</li><li>单台 P4 的专属配置里<strong>不能含 <code>p4</code> 项</strong>,否则会被静默忽略(不报错)。</li></ul><p>每台 P4 都要用 Helix Core 扩展(推荐)或 trigger 通知 Swarm 事件,两者不能混用,且要给每台设好 trigger token 和 Swarm host 变量。<strong>配置里要用完整 URL</strong>,例如 <code>https://&lt;swarm-url&gt;:&lt;port&gt;/serverA</code>。</p><p>给每台 P4 配 cron job,把所有 server url 加进去:</p><div class="language-text line-numbers-mode" data-highlighter="prismjs" data-ext="text"><pre><code><span class="line">http://localhost:&lt;port&gt;/serverA</span>
<span class="line">http://localhost:&lt;port&gt;/serverB</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><p>如果 worker cron 不工作,手动建一个 <code>/etc/crontab</code> job:</p><div class="language-text line-numbers-mode" data-highlighter="prismjs" data-ext="text"><pre><code><span class="line">* * * * * root [ -x /opt/perforce/swarm/p4-bin/scripts/swarm-cron.sh ] &amp;&amp; /opt/perforce/swarm/p4-bin/scripts/swarm-cron.sh</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>登录 Swarm 后点 serverA 或 serverB 即可进各自的 Swarm 页面。</p><h3 id="worker-cron-排查" tabindex="-1"><a class="header-anchor" href="#worker-cron-排查"><span>worker / cron 排查</span></a></h3><p>worker 处理队列任务(建/更新 review、评论、发邮件)。任务文件在 <code>/opt/perforce/swarm/data/queue</code>,完成即删。如果文件数持续增长而非稳定,就调大 <code>config.php</code> 里的 <code>workers</code>。</p><p><code>/etc/cron.d/helix-swarm</code> 指向 <code>swarm-cron.sh</code>,内容应为:</p><div class="language-text line-numbers-mode" data-highlighter="prismjs" data-ext="text"><pre><code><span class="line">* * * * * nobody [ -x /opt/perforce/swarm/p4-bin/scripts/swarm-cron.sh ] &amp;&amp; /opt/perforce/swarm/p4-bin/scripts/swarm-cron.sh</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p><code>swarm-cron.sh</code> 用 wget 或 curl 拉 worker:</p><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code><span class="line"><span class="token function">wget</span> <span class="token parameter variable">--quiet</span> --no-check-certificate --output-document /dev/null <span class="token parameter variable">--timeout</span> <span class="token number">1</span> <span class="token string">&quot;http://&lt;swarm-url&gt;/queue/worker&quot;</span></span>
<span class="line"><span class="token function">curl</span> <span class="token parameter variable">--silent</span> <span class="token parameter variable">--insecure</span> <span class="token parameter variable">--output</span> /dev/null --max-time <span class="token number">1</span> <span class="token string">&quot;http://&lt;swarm-url&gt;/queue/worker&quot;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><p><code>/opt/perforce/etc/swarm-cron-hosts.conf</code> 指定连接类型、hostname 和端口,格式 <code>[http[s]://]&lt;swarm-host&gt;[:&lt;port&gt;]</code>(默认 http、端口 80,hostname 必填)。</p><p>最重要的一步是手动跑一次 <code>swarm-cron.sh</code> 验证。如果报 <code>Error (4) starting a worker ... via [wget]</code>,先手动跑那条 wget 命令,再看队列状态:</p><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code><span class="line"><span class="token function">curl</span> http://<span class="token operator">&lt;</span>swarm-url<span class="token operator">&gt;</span>/queue/status</span>
<span class="line"><span class="token comment"># {&quot;tasks&quot;:0,&quot;futureTasks&quot;:0,&quot;workers&quot;:6,&quot;maxWorkers&quot;:8,...}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><p>workers 数不为 0 就正常。用 <code>grep CRON /var/log/syslog</code> 确认 cron 在跑。cron 还是不行就重启:<code>service cron restart</code>。</p><h2 id="触发-jenkins-构建" tabindex="-1"><a class="header-anchor" href="#触发-jenkins-构建"><span>触发 Jenkins 构建</span></a></h2><p>让 Swarm review 触发 Jenkins job 做 CI。</p><p><strong>生成 Jenkins API token</strong>:在 Jenkins 用户配置里生成。</p><p><strong>在 Swarm 里建一个 test</strong>:</p><ul><li><strong>URL</strong>:Jenkins job 的 url。</li><li><strong>Body</strong>:传给 Jenkins job 的参数。</li><li><strong>Iterate tests for affected projects and branches</strong>:为每个关联的 branch/project 各建一个 test run,<code>{projects}</code>、<code>{branches}</code>、<code>{branch}</code> 参数会用在 test 名上。</li><li><strong>Header</strong>:<code>name=value</code> 形式传给 test suite。</li></ul><p><strong>Authorization 值怎么来</strong>:把用户名和 Jenkins API token 用冒号拼接后做 base64。</p><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code><span class="line"><span class="token comment"># test.txt 内容为 &lt;jenkins-user&gt;:&lt;api-token&gt;</span></span>
<span class="line"><span class="token function">cat</span> test.txt <span class="token operator">|</span> base64 <span class="token parameter variable">-w</span> <span class="token number">0</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><p>填进 Header 时别忘了前面加 <code>Basic </code>。</p><p><strong>Jenkins job 参数</strong>:按需接收,但<strong>必须有 pass 和 fail 参数</strong>,否则 Swarm 拿不到构建结果。</p><p><strong>把 test 加进 workflow</strong>,<code>When</code> 选项:</p><ul><li><code>On Update</code>:review 创建、提交且内容有变、更新且内容有变时触发。</li><li><code>On Submit</code>:pre-commit review 提交或 post-commit review 创建时触发。</li><li><code>On Demand</code>:不自动跑,在 review 页 Tests 对话框手动跑。</li></ul><p><code>Blocks</code> 选项:<code>Nothing</code>(失败不挡批准)、<code>Approve</code>(失败则不能批准)。</p><p>最后在项目里启用 workflow、配好 branch。注意:如果中止 Jenkins 构建,Swarm 上的 test 结果是 failed。</p><h3 id="swarm-回调-url-可选" tabindex="-1"><a class="header-anchor" href="#swarm-回调-url-可选"><span>Swarm 回调 URL(可选)</span></a></h3><p>Jenkins 把结果回写 Swarm 的几种方式:</p><ul><li><p><code>{update}</code>:POST JSON 到 <code>{update}</code> URL,把 test 结果消息写回。<code>status</code> 取 <code>running</code>/<code>pass</code>/<code>fail</code>;最多 10 条 message,每条最多 80 字符(超出截断)。2019.3+ 推荐这个。</p><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code><span class="line"><span class="token function">curl</span> <span class="token parameter variable">-v</span> <span class="token parameter variable">-X</span> POST <span class="token parameter variable">-H</span> <span class="token string">&quot;Content-Type:application/json&quot;</span> <span class="token punctuation">\\</span></span>
<span class="line">  http://<span class="token operator">&lt;</span>swarm-url<span class="token operator">&gt;</span>/serverA/api/v10/testruns/6/<span class="token operator">&lt;</span>run-uuid<span class="token operator">&gt;</span>/ <span class="token parameter variable">-d</span> @D:<span class="token punctuation">\\</span>swarm.json</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div></li><li><p><code>{pass}</code> / <code>{fail}</code>:GET 或 POST 都行,直接置结果。</p><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code><span class="line"><span class="token function">curl</span> http://<span class="token operator">&lt;</span>swarm-url<span class="token operator">&gt;</span>/serverA/api/v10/testruns/8/pass/<span class="token operator">&lt;</span>run-uuid<span class="token operator">&gt;</span>/</span>
<span class="line"><span class="token function">curl</span> http://<span class="token operator">&lt;</span>swarm-url<span class="token operator">&gt;</span>/serverA/api/v10/testruns/8/fail/<span class="token operator">&lt;</span>run-uuid<span class="token operator">&gt;</span>/</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div></li></ul><h3 id="自动提交-api-可选" tabindex="-1"><a class="header-anchor" href="#自动提交-api-可选"><span>自动提交 API(可选)</span></a></h3><p>文档:<a href="https://www.perforce.com/manuals/swarm/Content/Swarm/swarm-apidoc.html" target="_blank" rel="noopener noreferrer">Swarm API</a>。先取 ticket:</p><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code><span class="line">p4 <span class="token parameter variable">-p</span> <span class="token operator">&lt;</span>P4SERVER<span class="token operator">&gt;</span>:1666 <span class="token parameter variable">-u</span> <span class="token operator">&lt;</span>user<span class="token operator">&gt;</span> login <span class="token parameter variable">-p</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>提交(transition):</p><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code><span class="line"><span class="token function">curl</span> <span class="token parameter variable">-H</span> <span class="token string">&quot;Content-Type: application/json&quot;</span> <span class="token parameter variable">-X</span> POST <span class="token punctuation">\\</span></span>
<span class="line">  <span class="token parameter variable">-u</span> <span class="token string">&quot;&lt;swarm-user&gt;:&lt;api-token&gt;&quot;</span> <span class="token parameter variable">-d</span> @swarm.json <span class="token punctuation">\\</span></span>
<span class="line">  <span class="token string">&quot;http://&lt;swarm-url&gt;/api/v11/reviews/<span class="token variable">\${params.review}</span>/transitions&quot;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><div class="language-json line-numbers-mode" data-highlighter="prismjs" data-ext="json"><pre><code><span class="line"><span class="token punctuation">{</span></span>
<span class="line">  <span class="token property">&quot;transition&quot;</span><span class="token operator">:</span> <span class="token string">&quot;approved:commit&quot;</span><span class="token punctuation">,</span></span>
<span class="line">  <span class="token property">&quot;fixStatus&quot;</span><span class="token operator">:</span> <span class="token string">&quot;closed&quot;</span><span class="token punctuation">,</span></span>
<span class="line">  <span class="token property">&quot;cleanup&quot;</span><span class="token operator">:</span> <span class="token boolean">true</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><code>\${params.review}</code> 来自 <code>{review}</code>。</p><h3 id="jenkins-https-url-报错" tabindex="-1"><a class="header-anchor" href="#jenkins-https-url-报错"><span>Jenkins HTTPS URL 报错</span></a></h3><p>如果触发时 Swarm 日志报 <code>stream_socket_enable_crypto(): SSL operation failed</code>,通常是 Jenkins 那端证书链不全——需要用完整链的证书:服务器证书 + 中间证书 + 根证书。</p><h2 id="api" tabindex="-1"><a class="header-anchor" href="#api"><span>API</span></a></h2><p>参考 <a href="https://help.perforce.com/helix-core/helix-swarm/swarm/current/Content/Swarm/swarm-apidoc_api_versions.html" target="_blank" rel="noopener noreferrer">Swarm API 文档</a>。查版本:</p><div class="language-text line-numbers-mode" data-highlighter="prismjs" data-ext="text"><pre><code><span class="line">http://&lt;swarm-url&gt;:&lt;port&gt;/api/version</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h2 id="手动安装-helix-swarm-p4-extension" tabindex="-1"><a class="header-anchor" href="#手动安装-helix-swarm-p4-extension"><span>手动安装 helix-swarm.p4-extension</span></a></h2><p><code>helix-swarm.p4-extension</code> 是 Swarm 和 Helix Core 集成的扩展,影响 update review、review 提交后自动关闭等功能。装 Swarm 时会自动装这个扩展,如果不小心删了可以手动重装。</p><blockquote><p>缺点:提交很多文件时会被这个扩展限制,需要把限制设为 false 才行。</p></blockquote><p>扩展文件在 Swarm 宿主机的 <code>/opt/perforce/swarm/p4-bin/extensions/</code>,拷出来:</p><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code><span class="line"><span class="token function">docker</span> <span class="token function">cp</span> <span class="token operator">&lt;</span>container-id<span class="token operator">&gt;</span>:/opt/perforce/swarm/p4-bin/extensions/helix-swarm.p4-extension /root/projectName-swarm/helix-swarm.p4-extension</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>删旧扩展、装新扩展(确保当前目录有该文件):</p><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code><span class="line">p4 extension <span class="token parameter variable">--delete</span> Perforce::helix-swarm <span class="token parameter variable">--yes</span></span>
<span class="line">p4 extension <span class="token parameter variable">--yes</span> <span class="token parameter variable">--install</span> helix-swarm.p4-extension</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><p>建全局配置(若不存在):</p><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code><span class="line">p4 extension <span class="token parameter variable">--configure</span> Perforce::helix-swarm</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>spec 文件里关键是 <code>ExtConfig</code> 段——填 <code>Swarm-Token</code>(从 Swarm 取)和 <code>Swarm-URL</code>,<code>ExtEnabled</code> 设 <code>true</code>。</p><p>建实例配置启用扩展、验证、查看:</p><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code><span class="line">p4 extension <span class="token parameter variable">--configure</span> Perforce::helix-swarm <span class="token parameter variable">--name</span> projectName-swarm</span>
<span class="line">p4 extension <span class="token parameter variable">--run</span> projectName-swarm <span class="token function">ping</span>          <span class="token comment"># 返回 OK 即正常</span></span>
<span class="line">p4 extension <span class="token parameter variable">--list</span> <span class="token parameter variable">--type</span> instance</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>禁用扩展:把 <code>ExtEnabled</code> 改成 <code>false</code>(<code>p4 extension --configure Perforce::helix-swarm</code>)。</p><h2 id="进阶-接-claude-做-ai-review" tabindex="-1"><a class="header-anchor" href="#进阶-接-claude-做-ai-review"><span>进阶:接 Claude 做 AI Review</span></a></h2><p>这是个进阶玩法:当 Jenkins 经 Swarm Workflow 的 <strong>test</strong> 阶段触发构建时,脚本自动用 Claude 对 review 的代码变更做 review,并把结果以 inline comment 的形式回写 Swarm。代码与示例 review 见内部仓库。</p><h3 id="功能" tabindex="-1"><a class="header-anchor" href="#功能"><span>功能</span></a></h3><p>脚本会自动:</p><ol><li>取本次 review 最新版本文件的 diff。</li><li>把每个文件的 diff 发给 Claude 做代码审查。</li><li>在 Swarm review 页面发两类 comment:<strong>Summary comment</strong>(所有文件问题汇总,先发)和 <strong>Inline comment</strong>(定位到具体文件行号的建议,后发)。</li></ol><p>二进制文件、美术资源(<code>.uasset</code>、<code>.fbx</code>、<code>.png</code> 等)会自动跳过,不发给 AI。</p><h3 id="环境与配置-exe-运行可忽略环境部分" tabindex="-1"><a class="header-anchor" href="#环境与配置-exe-运行可忽略环境部分"><span>环境与配置(exe 运行可忽略环境部分)</span></a></h3><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code><span class="line">pip <span class="token function">install</span> <span class="token assign-left variable">p4python</span><span class="token operator">==</span><span class="token number">2024.1</span>.*    <span class="token comment"># 版本需与 P4 Server API 匹配</span></span>
<span class="line">pip <span class="token function">install</span> requests             <span class="token comment"># 需 Python &gt;= 3.10</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><p>编辑同目录的 <code>swarm_ai_review.ini</code>:</p><div class="language-ini line-numbers-mode" data-highlighter="prismjs" data-ext="ini"><pre><code><span class="line"><span class="token section"><span class="token punctuation">[</span><span class="token section-name selector">swarm</span><span class="token punctuation">]</span></span></span>
<span class="line"><span class="token key attr-name">url</span>    <span class="token punctuation">=</span> <span class="token value attr-value">http://&lt;swarm-host&gt;:&lt;port&gt;/</span></span>
<span class="line"><span class="token key attr-name">user</span>   <span class="token punctuation">=</span> <span class="token value attr-value">&lt;swarm-user&gt;</span></span>
<span class="line"><span class="token key attr-name">ticket</span> <span class="token punctuation">=</span> <span class="token value attr-value">&lt;p4-ticket&gt;</span></span>
<span class="line"></span>
<span class="line"><span class="token section"><span class="token punctuation">[</span><span class="token section-name selector">p4</span><span class="token punctuation">]</span></span></span>
<span class="line"><span class="token key attr-name">port</span>   <span class="token punctuation">=</span> <span class="token value attr-value">&lt;P4SERVER&gt;:1666        ; 例如 ssl:&lt;P4SERVER&gt;:1666</span></span>
<span class="line"><span class="token key attr-name">user</span>   <span class="token punctuation">=</span> <span class="token value attr-value">&lt;p4-user&gt;</span></span>
<span class="line"><span class="token key attr-name">ticket</span> <span class="token punctuation">=</span> <span class="token value attr-value">&lt;p4-ticket&gt;</span></span>
<span class="line"></span>
<span class="line"><span class="token section"><span class="token punctuation">[</span><span class="token section-name selector">claude</span><span class="token punctuation">]</span></span></span>
<span class="line"><span class="token key attr-name">url</span>        <span class="token punctuation">=</span> <span class="token value attr-value">&lt;claude-api-url&gt;/v1/messages</span></span>
<span class="line"><span class="token key attr-name">model</span>      <span class="token punctuation">=</span> <span class="token value attr-value">claude-opus-4-6</span></span>
<span class="line"><span class="token key attr-name">max_tokens</span> <span class="token punctuation">=</span> <span class="token value attr-value">4096</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>Claude API Key 通过环境变量传入,不写进配置文件:</strong></p><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code><span class="line"><span class="token builtin class-name">export</span> <span class="token assign-left variable">ClaudeKey</span><span class="token operator">=</span><span class="token string">&quot;&lt;your-api-key&gt;&quot;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>在 Jenkins 里设成 Secret Text 类型的 Credential,用 <code>withCredentials</code> 注入。</p><h3 id="运行与-jenkins-集成" tabindex="-1"><a class="header-anchor" href="#运行与-jenkins-集成"><span>运行与 Jenkins 集成</span></a></h3><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code><span class="line">python swarm_ai_review.py --review-id <span class="token number">10129</span></span>
<span class="line"><span class="token comment"># 或通过环境变量(Jenkins 自动注入)</span></span>
<span class="line"><span class="token builtin class-name">export</span> <span class="token assign-left variable">SWARM_REVIEW_ID</span><span class="token operator">=</span><span class="token number">10129</span></span>
<span class="line">python swarm_ai_review.py</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>Jenkinsfile 的 test 阶段:</p><div class="language-groovy line-numbers-mode" data-highlighter="prismjs" data-ext="groovy"><pre><code><span class="line"><span class="token function">stage</span><span class="token punctuation">(</span><span class="token string">&#39;AI Code Review&#39;</span><span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">    environment <span class="token punctuation">{</span></span>
<span class="line">        SWARM_REVIEW_ID <span class="token operator">=</span> <span class="token interpolation-string"><span class="token string">&quot;</span><span class="token interpolation"><span class="token interpolation-punctuation punctuation">\${</span><span class="token expression">params<span class="token punctuation">.</span>SWARM_REVIEW</span><span class="token interpolation-punctuation punctuation">}</span></span><span class="token string">&quot;</span></span>   <span class="token comment">// Swarm 注入的参数</span></span>
<span class="line">        ClaudeKey       <span class="token operator">=</span> <span class="token function">credentials</span><span class="token punctuation">(</span><span class="token string">&#39;claude-api-key&#39;</span><span class="token punctuation">)</span></span>
<span class="line">    <span class="token punctuation">}</span></span>
<span class="line">    steps <span class="token punctuation">{</span></span>
<span class="line">        sh <span class="token string">&#39;python3 /path/to/swarm_ai_review.py&#39;</span></span>
<span class="line">    <span class="token punctuation">}</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="整体流程" tabindex="-1"><a class="header-anchor" href="#整体流程"><span>整体流程</span></a></h3><div class="language-text line-numbers-mode" data-highlighter="prismjs" data-ext="text"><pre><code><span class="line">Jenkins Trigger (SWARM_REVIEW_ID)</span>
<span class="line">  → [1] GET /api/v11/reviews/{id},取 versions[] 中 time 最大的版本,得 shelved CL</span>
<span class="line">  → [2] P4Python: describe -du -S {changelist},按文件块拆分 diff、构建 {新行号→行内容} 映射</span>
<span class="line">  → [3] 逐文件 POST Claude API(跳过二进制/资源),要求返回 JSON array</span>
<span class="line">        [{&quot;line&quot;: N, &quot;severity&quot;: &quot;...&quot;, &quot;comment&quot;: &quot;...&quot;}]</span>
<span class="line">  → [4] POST /api/v9/comments(Summary,无 context)</span>
<span class="line">  → [5] POST /api/v9/comments × N(inline,含 file + rightLine + content)</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="几个关键实现点" tabindex="-1"><a class="header-anchor" href="#几个关键实现点"><span>几个关键实现点</span></a></h3><p><strong>取 shelved diff</strong>:P4Python 默认 tagged 模式返回结构化 dict,<code>describe -du</code> 的 diff 文本在 tagged 模式下输出不完整。临时关掉 tagged,行为就和 CLI 一致,返回 <code>list[str]</code>:</p><div class="language-python line-numbers-mode" data-highlighter="prismjs" data-ext="py"><pre><code><span class="line">p4<span class="token punctuation">.</span>tagged <span class="token operator">=</span> <span class="token boolean">False</span></span>
<span class="line">lines <span class="token operator">=</span> p4<span class="token punctuation">.</span>run<span class="token punctuation">(</span><span class="token string">&quot;describe&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;-du&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;-S&quot;</span><span class="token punctuation">,</span> <span class="token builtin">str</span><span class="token punctuation">(</span>changelist<span class="token punctuation">)</span><span class="token punctuation">)</span></span>
<span class="line">p4<span class="token punctuation">.</span>tagged <span class="token operator">=</span> <span class="token boolean">True</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>拆分 diff</strong>:按 <code>==== //depot/path/file ====</code> 头部正则拆文件块,跳过 <code>SKIP_EXTENSIONS</code>,超过 <code>MAX_DIFF_CHARS</code>(默认 12000)截断。</p><p><strong>hunk map</strong>:解析 unified diff 的 <code>@@ -a,b +c,d @@</code>,追踪新文件行号,返回 <code>{int: str}</code> 映射,给 inline comment 提供 <code>context[content]</code> 做行定位。</p><p><strong>调 Claude</strong>:发 diff,要求返回 JSON array,字段 <code>line</code>(新文件行号)、<code>severity</code>(error/warning/info)、<code>comment</code>(建议)。Claude 偶尔会用 <code>\`\`\`json \`\`\`</code> 包裹,用正则清理后再解析。</p><p><strong>inline comment API</strong>:</p><div class="language-text line-numbers-mode" data-highlighter="prismjs" data-ext="text"><pre><code><span class="line">POST /api/v9/comments</span>
<span class="line">topic              = reviews/{review_id}</span>
<span class="line">body               = **[AI Review] [ERROR]** ...</span>
<span class="line">context[file]      = //depot/mainline/Source/GameManager.cpp</span>
<span class="line">context[rightLine] = 42</span>
<span class="line">context[content]   =    return ptr-&gt;GetValue();   // 行内容(≤200 字符)</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><code>context[rightLine]</code> 对应 diff 右侧(新文件)行号,Swarm 用 <code>context[content]</code> 做行定位校验。</p><p><strong>取最新版本</strong>:Swarm review 每次更新文件会新增一条 version。用 <code>max(versions, key=lambda v: v.get(&quot;time&quot;, 0))</code> 而非 <code>versions[-1]</code>,避免依赖 Swarm 返回顺序。</p><p>配置扩展点:<code>SKIP_EXTENSIONS</code>(跳过的文件类型)、<code>MAX_DIFF_CHARS</code>(单文件 diff 上限)、<code>SYSTEM_PROMPT</code>(审查规则)、ini 里的 <code>max_tokens</code>。</p><h2 id="卸载与排错" tabindex="-1"><a class="header-anchor" href="#卸载与排错"><span>卸载与排错</span></a></h2><h3 id="卸载" tabindex="-1"><a class="header-anchor" href="#卸载"><span>卸载</span></a></h3><p>参考<a href="https://www.perforce.com/manuals/swarm/Content/Swarm/admin.uninstall.html" target="_blank" rel="noopener noreferrer">官方卸载文档</a>。删 <code>P4.Swarm.URL</code> 属性时如果报 <code>No such property &#39;P4.Swarm.URL&#39;</code>:</p><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code><span class="line">p4 property <span class="token parameter variable">-l</span> <span class="token parameter variable">-A</span></span>
<span class="line"><span class="token comment"># :: &gt;&gt; P4.Swarm.URL = http://HelixSwarmHost (any) #none</span></span>
<span class="line">p4 property <span class="token parameter variable">-d</span> <span class="token parameter variable">-n</span> P4.Swarm.URL <span class="token parameter variable">-s</span> <span class="token number">0</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="常见问题" tabindex="-1"><a class="header-anchor" href="#常见问题"><span>常见问题</span></a></h3><p><strong>打开页面报 ticket 错误(p4 admin 账号 ticket 过期)。</strong> 原因:在 Swarm 上建组时,Swarm 会建一个密码 12 小时过期的组,导致 p4 admin 账号 ticket 失效。建组后立刻把过期设为 unset。临时修复——进容器手动生成 ticket,更新到 <code>config.php</code> 再重启容器:</p><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code><span class="line"><span class="token function">docker</span> <span class="token builtin class-name">exec</span> <span class="token parameter variable">-it</span> <span class="token operator">&lt;</span>container-id<span class="token operator">&gt;</span> /bin/bash</span>
<span class="line">p4 <span class="token parameter variable">-p</span> <span class="token operator">&lt;</span>P4SERVER<span class="token operator">&gt;</span>:1666 <span class="token parameter variable">-u</span> <span class="token operator">&lt;</span>user<span class="token operator">&gt;</span> login <span class="token parameter variable">-p</span></span>
<span class="line">:: 把 ticket 写进 config.php</span>
<span class="line"><span class="token function">vim</span> swarm-data/config.php</span>
<span class="line"><span class="token function">docker</span> restart <span class="token operator">&lt;</span>container-id<span class="token operator">&gt;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>页面提示没有 worker(各种操作都可能出问题)。</strong> 进容器检查 <code>/etc/crontab</code> 是否有那行 <code>swarm-cron.sh</code>,没有就 <code>docker cp</code> 拷一份进去;有的话检查 <code>swarm-data/docker/swarm-cron-hosts.conf</code> 里的 Swarm 地址是否正确,改对后重启。</p><p><strong>页面打不开、端口不通。</strong> 检查 Apache 配置 <code>swarm-data/docker/sites-available/perforce-swarm-site.conf</code>,改对后重启 Swarm。</p><p><strong>通过 Swarm 提交后 review 无法自动关闭。</strong> 依次检查:有没有 worker(按上面方法处理)→ <code>p4 extension --list --type instance</code> 看扩展实例,没输出说明扩展没了,手动重装 → 检查扩展配置是否被禁用(<code>p4 extension --configure Perforce::helix-swarm</code> 全局、<code>--name &lt;配置名&gt;</code> 实例),禁用了就打开。</p>`,180)]))}const c=n(t,[["render",i],["__file","p4-swarm.html.vue"]]),d=JSON.parse('{"path":"/Tools/VCS/P4/p4-swarm.html","title":"P4 Swarm 部署与使用","lang":"en-US","frontmatter":{"date":"2024-01-12T20:04:44.000Z","tag":["Tools","VCS","Perforce"]},"git":{"createdTime":1782480255000,"updatedTime":1782480255000,"contributors":[{"name":"BanMing","username":"BanMing","email":"ban-ming@foxmail.com","commits":1,"url":"https://github.com/BanMing"},{"name":"Claude Opus 4.7","username":"Claude Opus 4.7","email":"noreply@anthropic.com","commits":1,"url":"https://github.com/Claude Opus 4.7"}]},"readingTime":{"minutes":16.96,"words":5088},"filePathRelative":"Tools/VCS/P4/p4-swarm.md","localizedDate":"January 12, 2024","excerpt":"\\n<p>Swarm 是 Perforce 官方的代码评审 Web 系统,和 Helix Core(P4)集成做 pre-commit / post-commit review。这篇从概念用法讲到部署:在 P4V 里怎么发起和处理 review、Docker 怎么起一个新 Swarm、<code>config.php</code> 怎么配、Nginx 怎么套 HTTPS、一个 Swarm 怎么连多台 P4、怎么触发 Jenkins 构建、API 怎么用、再到接 Claude 做 AI Review,最后是卸载和排错。下文所有内部主机、IP、账号密码都用占位符代替,换成你自己的值即可。</p>\\n<h2>Review 工作流(P4V 端)</h2>"}');export{c as comp,d as data};
